var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"…보고 싶구나, 니콜.","JPN":"……会いたい、ニコル。","ENG":"...I miss you, Nicole.","TWN":"……真想見你，妮可。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 몸을 혼자 두고… 언제 돌아오는 것이냐.","JPN":"吾輩を一人にして……いつ帰ってくるつもりだ。","ENG":"Leaving me all alone... When are you coming back?","TWN":"把我一個人丟下……你究竟什麼時候才回來？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"모모?!","JPN":"モモ！？","ENG":"Momo?!","TWN":"莫莫？！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"미안.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"계속 곁에 있었어야 했는데…","JPN":"ずっとそばにいるべきだったのに……","ENG":"I should've stayed by your side the whole time...","TWN":"我應該一直陪在你身邊的……"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"못 지켜줘서 미안해요.","JPN":"守ってあげられなくてごめんなさい。","ENG":"I'm sorry I couldn't protect you.","TWN":"沒能保護你，對不起。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"정말 벌써 퇴원해도 괜찮겠어요?","JPN":"本当にもう退院して大丈夫なんですか？","ENG":"Are you really all right to be discharged already?","TWN":"真的已經可以出院了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"말했잖아. 별것 아니니까 금방 나을 거라고.","JPN":"言ったでしょ。大した傷じゃないからすぐ治るって。","ENG":"I told you. It's nothing serious, I'll recover soon enough.","TWN":"我不是說了嗎？沒什麼大不了的，很快就會好。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"사흘 동안 금식이라 인삼주스를 못 먹는 게 뼈아프긴 하지만… 어쩔 수 없, 콜록-","JPN":"3日絶食だから高麗人参ジュースが飲めないのは辛いけど……仕方な、げほっ。","ENG":"Three days of fasting and no ginseng juice hurts, but... it can't be hel– *Cough*","TWN":"雖然得禁食三天，不能喝人蔘汁這點很痛苦……但也沒辦法，咳—"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…입에서 피가 나는데요?","JPN":"……口から血を吐きましたけど？","ENG":"...You're bleeding from the mouth.","TWN":"……你嘴角在流血耶？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이건… 나쁜 피를 걸러내는 거야. 오히려 좋은 거지.","JPN":"これは……悪い血を出してるの。逆にいいこと。","ENG":"This is... just filtering out bad blood. It's actually a good thing.","TWN":"這是……排出壞血，反而是好事。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아무튼, 오늘 만나자고 한 용건은 그런 게 아니야.","JPN":"とにかく、今日呼び出した用件はそのことじゃなくて。","ENG":"Anyway, that's not why I asked to meet today.","TWN":"總之，今天約你出來不是為了這個。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아, 그랬죠.","JPN":"あ、そうでしたね。","ENG":"Ah, right.","TWN":"啊，對。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그럼… 모모가 있던 시설의 보안카메라 복원에 성공한 건가요?","JPN":"では……モモがいた施設の防犯カメラのデータを復元できたんですか？","ENG":"Then... did you manage to restore the security camera footage from the facility where Momo was?","TWN":"那麼……已經成功復原莫莫所在設施的監控畫面了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"침식 오염도가 높아서, 완벽한 복원에는 실패 했어.","JPN":"侵食汚染度が高すぎて完璧にはいかなかった。","ENG":"The Corruption Level was too severe for a full restoration.","TWN":"因為侵蝕污染度太高，沒能完全復原。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"하지만 손상이 덜한 녹화 프레임 몇 개를 살리는 덴 성공했지.","JPN":"でも損傷が少なかったフレームの一部は復元できたよ。","ENG":"But we did manage to salvage a few frames with minimal damage.","TWN":"不過，還是成功搶救了幾個受損比較不嚴重的畫面。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"적어도… 그곳에 뭐가 다녀간 건지는 알겠더라.","JPN":"少なくとも……あそこに何が来ていたかはわかった。","ENG":"At the very least... we know what passed through there.","TWN":"至少……能確認有什麼東西曾經去過那裡。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"다녀간… 무언가?","JPN":"何かが……来ていた？","ENG":"Something... passed through...?","TWN":"去過那裡的……什麼？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이거야.","JPN":"これ。","ENG":"This.","TWN":"就是這個。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"모모가 있던 방에서 확인된 존재의 정체.","JPN":"モモがいた部屋で確認された存在の正体。","ENG":"The identity of the entity confirmed in the room where Momo was.","TWN":"在莫莫房間內確認到的存在。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"이건… 누구죠?","JPN":"これは……誰ですか？","ENG":"Who... is that?","TWN":"這是……誰？"},"stage":{"bg":"OMEN_INTRO_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"타기리온.","JPN":"タギリオン。","ENG":"Thagirion.","TWN":"塔基里翁。"},"stage":{"bg":"OMEN_INTRO_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그라운드 원을 비롯해… 관리국이 지키던 도시들을 하룻밤에 쑥대밭으로 만든…","JPN":"グラウンド・ワンをはじめとして……管理局が守っていた都市を一晩で滅茶苦茶にした……","ENG":"The Demon Lord who turned Ground One... and the cities the Administration protected into ruins overnight.","TWN":"讓包括G1在內，由管理局守護的多座城市，一夜之間化為焦土的……"},"stage":{"bg":"OMEN_INTRO_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕이야.","JPN":"魔王。","ENG":"A Demon Lord.","TWN":"魔王。"},"stage":{"bg":"OMEN_INTRO_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕 타기리온이 모모의 앞에 나타나 손길을 뻗었고…","JPN":"魔王タギリオンがモモの前に現れて手を伸ばし……","ENG":"Demon Lord Thagirion appeared before Momo and reached out to her...","TWN":"魔王塔基里翁出現在莫莫面前，向她伸出手……"},"stage":{"bg":"OMEN_INTRO_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…모모의 뿔이 사라지면서, 그대로 잠들었어.","JPN":"……角が消え、モモはそのまま眠った。","ENG":"...And as Momo's horns vanished, she fell into a deep sleep.","TWN":"……隨著莫莫的角消失，她就這樣陷入沉睡。"},"stage":{"bg":"OMEN_INTRO_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"순전히 내 추측이지만…","JPN":"これは個人的な推測だけど……","ENG":"This is purely my speculation, but...","TWN":"純屬我的推測……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};